/* ===== 第3章专属：交换律验证区配置 ===== */
const VERIFY_OPTIONS = ['R', "R'", 'U', "U'", 'F', "F'"] as const
type VerifyOption = typeof VERIFY_OPTIONS[number]

/** 将选择映射为可显示矩阵 */
function optionToMatrix(opt: VerifyOption): number[][] {
  const face = opt[0] // R/U/F
  const prime = opt.length > 1 // 是否有 '
  const m = ROTATION_MATRICES[face]
  return prime ? inverseMatrix(m) : m
}

