/** 通用自测题选项组件 */
function QuizOptions({ options, explanation }: {
  options: { label: string; correct: boolean }[]
  explanation: string
}) {
  const [selected, setSelected] = useState<number | null>(null)

  return (
    <div>
      {options.map((opt, i) => (
        <button
          key={i}
          onClick={() => setSelected(i)}
          style={{
            display: 'block', width: '100%', textAlign: 'left',
            padding: '0.4rem 0.8rem', marginBottom: '0.4rem',
            borderRadius: '6px', border: '1px solid var(--rule)',
            background: selected === i
              ? opt.correct ? '#dcfce7' : '#fee2e2'
              : 'var(--bg)',
            fontSize: '0.82rem',
            cursor: 'pointer',
          }}
        >
          {opt.label}
          {selected === i && (
            <span style={{ marginLeft: '0.5rem' }}>
              {opt.correct ? '✅' : '❌'}
            </span>
          )}
        </button>
      ))}
      {selected !== null && (
        <p style={{
          marginTop: '0.6rem', padding: '0.6rem',
          background: options[selected].correct ? '#dcfce7' : '#fef3c7',
          borderRadius: '6px', fontSize: '0.8rem',
        }}>
          {options[selected].correct ? '🎉 ' : '💡 '}
          {explanation}
        </p>
      )}
    </div>
  )
}

/* ============================ 第3章专属：交换律验证区 ============================ */

interface ComposeVerifyProps {
  leftCubeRef: React.RefObject<Cube3DViewHandle | null>
  rightCubeRef: React.RefObject<Cube3DViewHandle | null>
}

/** 第3章：交换律验证区（双魔方并排对比） */
function ComposeVerify({ leftCubeRef, rightCubeRef }: ComposeVerifyProps) {
  const [step1, setStep1] = useState<VerifyOption>('R')
  const [step2, setStep2] = useState<VerifyOption>('U')
  const [resultAB, setResultAB] = useState<number[][] | null>(null)
  const [resultBA, setResultBA] = useState<number[][] | null>(null)
  const [compared, setCompared] = useState(false)

  /** 执行对比：双魔方同时演示，左=①→②，右=②→① */
  const handleCompare = useCallback(() => {
    const m1 = optionToMatrix(step1)
    const m2 = optionToMatrix(step2)
    const ab = multiply3x3(m1, m2)
    const ba = multiply3x3(m2, m1)
    setResultAB(ab)
    setResultBA(ba)
    setCompared(true)

    // 双魔方同时重置
    leftCubeRef.current?.reset()
    rightCubeRef.current?.reset()

    // 先演示左边（①→②），再演示右边（②→①）
    setTimeout(() => {
      // 左：① → ②
      leftCubeRef.current?.executeMove(step1)
      setTimeout(() => leftCubeRef.current?.executeMove(step2), 350)

      // 等左边演示完再开始右边
      setTimeout(() => {
        rightCubeRef.current?.executeMove(step2)
        setTimeout(() => rightCubeRef.current?.executeMove(step1), 350)
      }, 1200)
    }, 500)
  }, [step1, step2, leftCubeRef, rightCubeRef])

  const same = resultAB && resultBA ? matrixEqual(resultAB, resultBA) : null

  return (
    <div className="card" style={{ marginBottom: '1rem' }}>
      <h3 style={{ fontSize: '0.9rem', fontWeight: 700, marginBottom: '0.8rem' }}>
        交换律验证区
      </h3>
      <p style={{ fontSize: '0.8rem', color: 'var(--ink2)', marginBottom: '0.8rem' }}>
        选择两个操作，左右两个魔方同时演示不同顺序 —— 看最终结果是否一致。
      </p>

      {/* 操作选择器 */}
      <div style={{
        display: 'flex', alignItems: 'center', gap: '0.5rem', flexWrap: 'wrap',
        marginBottom: '0.8rem',
      }}>
        <span style={{ fontSize: '0.85rem', fontWeight: 600 }}>操作 ①</span>
        <select
          value={step1}
          onChange={(e) => { setStep1(e.target.value as VerifyOption); setCompared(false) }}
          style={{
            padding: '0.3rem 0.5rem', borderRadius: '6px',
            border: '1px solid var(--rule)', fontSize: '0.85rem',
            fontFamily: 'monospace', background: '#fff',
          }}
        >
          {VERIFY_OPTIONS.map((o) => <option key={o} value={o}>{FACE_NAME[o]}</option>)}
        </select>
        <span style={{ fontSize: '0.85rem', fontWeight: 600 }}>操作 ②</span>
        <select
          value={step2}
          onChange={(e) => { setStep2(e.target.value as VerifyOption); setCompared(false) }}
          style={{
            padding: '0.3rem 0.5rem', borderRadius: '6px',
            border: '1px solid var(--rule)', fontSize: '0.85rem',
            fontFamily: 'monospace', background: '#fff',
          }}
        >
          {VERIFY_OPTIONS.map((o) => <option key={o} value={o}>{FACE_NAME[o]}</option>)}
        </select>
      </div>

      <button className="btn btn-primary" style={{ fontSize: '0.82rem', marginBottom: '0.8rem' }} onClick={handleCompare}>
        执行并对比
      </button>

      {/* 结果展示 */}
      {compared && resultAB && resultBA && (
        <div>
          <div style={{
            marginBottom: '0.8rem', padding: '0.4rem 0.8rem', borderRadius: '6px',
            fontWeight: 700, fontSize: '0.88rem',
            background: same ? '#DCFCE7' : '#FEE2E2',
            color: same ? '#16A34A' : '#DC2626',
          }}>
            结果：{same ? '相同 ✓（极少数情况）' : '不同 ✗（绝大多数情况）'}
          </div>

          {/* 矩阵对比 */}
          <div style={{
            display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.8rem',
          }}>
            <div style={{ textAlign: 'center' }}>
              <p style={{ fontSize: '0.72rem', color: 'var(--muted)', marginBottom: '0.3rem' }}>
                ①→②：{step1}×{step2}
              </p>
              <MatrixDisplay data={resultAB} />
            </div>
            <div style={{ textAlign: 'center' }}>
              <p style={{ fontSize: '0.72rem', color: 'var(--muted)', marginBottom: '0.3rem' }}>
                ②→①：{step2}×{step1}
              </p>
              <MatrixDisplay data={resultBA} />
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

/* ============================ 第4章专属：撤销演示 ============================ */

function InverseDemo({ cubeRef }: { cubeRef: React.RefObject<Cube3DViewHandle | null> }) {
  const PREDEFINED_MOVES = ['R', 'U', 'F', "U'"] as const
  const [remainingIdx, setRemainingIdx] = useState<number>(PREDEFINED_MOVES.length)
  const [initialized, setInitialized] = useState(false)
  const [done, setDone] = useState(false)

  // 初始化：打乱魔方
  useEffect(() => {
    if (!initialized && cubeRef.current) {
      const timer = setTimeout(() => {
        cubeRef.current?.reset()
        let delay = 500
        for (const move of PREDEFINED_MOVES) {
          setTimeout(() => cubeRef.current?.executeMove(move), delay)
          delay += 350
        }
        setTimeout(() => {
          setInitialized(true)
          setRemainingIdx(PREDEFINED_MOVES.length)
        }, delay)
      }, 600)
      return () => clearTimeout(timer)
    }
  }, [initialized])

  /** 撤销一步 */
  const handleUndoStep = useCallback(() => {
    if (remainingIdx <= 0 || !cubeRef.current) return
    const idx = remainingIdx - 1
    const move = PREDEFINED_MOVES[idx]
    const reverse = move.endsWith("'") ? move[0] : move + "'"
    cubeRef.current.undoMove(reverse)
    const newIdx = idx
    setRemainingIdx(newIdx)
    if (newIdx === 0) setDone(true)
  }, [remainingIdx])

  /** 重置演示 */
  const handleReset = useCallback(() => {
    cubeRef.current?.reset()
    setInitialized(false)
    setDone(false)
  }, [])

  const remaining = PREDEFINED_MOVES.slice(0, remainingIdx)

  return (
    <div className="card" style={{ marginBottom: '1rem' }}>
      <h3 style={{ fontSize: '0.9rem', fontWeight: 700, marginBottom: '0.6rem' }}>
        🔄 撤销演示
      </h3>
      <p style={{ fontSize: '0.8rem', color: 'var(--ink2)', marginBottom: '0.8rem' }}>
        魔方已执行了 4 步操作。点击"撤销一步"，观察逆操作逐步还原。
      </p>

      {initialized && (
        <div style={{
          marginBottom: '0.8rem', padding: '0.4rem 0.8rem', borderRadius: '6px',
          background: done ? '#DCFCE7' : 'var(--bg2)',
          fontSize: '0.82rem',
        }}>
          {done ? (
            <span style={{ fontWeight: 700, color: '#16A34A' }}>🎉 还原成功！这就是逆矩阵的力量</span>
          ) : (
            <span>
              <strong>剩余操作：</strong>
              <span style={{ fontFamily: 'monospace', color: 'var(--accent)' }}>
                {remaining.length > 0 ? remaining.map(m => FACE_NAME[m] || m).join(' · ') : '（空）'}
              </span>
            </span>
          )}
        </div>
      )}

      <div style={{ display: 'flex', gap: '0.5rem' }}>
        <button
          className="btn btn-primary"
          style={{ fontSize: '0.82rem' }}
          onClick={handleUndoStep}
          disabled={!initialized || remainingIdx <= 0}
        >
          🔄 撤销一步
        </button>
        <button
          className="btn btn-outline"
          style={{ fontSize: '0.82rem' }}
          onClick={handleReset}
        >
          重置演示
        </button>
      </div>
    </div>
  )
}


/* ============================ 第5章专属：不变量观察器 ============================ */

function InvariantDemo({ cubeRef }: { cubeRef: React.RefObject<Cube3DViewHandle | null> }) {
  const [scrambled, setScrambled] = useState(false)
  const [count, setCount] = useState(0)
  const [showIllegal, setShowIllegal] = useState(false)

  const handleIllegalSwap = useCallback(() => { setShowIllegal(true) }, [])

  // 随机打乱：先重置再打乱 12 步，让用户观察中心块不动
  const handleScramble = useCallback(() => {
    cubeRef.current?.reset()
    setTimeout(() => cubeRef.current?.scramble(12), 300)
    setScrambled(true)
    setCount((c) => c + 1)
  }, [])

  // 重置为还原态
  const handleReset = useCallback(() => {
    cubeRef.current?.reset()
    setScrambled(false)
  }, [])

  return (
    <div className="card" style={{ marginBottom: '1rem', borderLeft: '4px solid var(--accent)' }}>
      <h3 style={{ fontSize: '0.9rem', fontWeight: 700, marginBottom: '0.6rem' }}>
        不变量观察器
      </h3>
      <p style={{ fontSize: '0.8rem', color: 'var(--ink2)', marginBottom: '0.8rem' }}>
        多次点击"随机打乱"并观察：无论怎么转，
        <strong>6 个中心块的相对位置始终不变</strong>——
        红对着橙，蓝对着绿，白对着黄。这就是魔方的"不变量"。
      </p>

      {scrambled && count > 0 && (
        <div style={{
          marginBottom: '0.8rem', padding: '0.5rem 0.8rem', borderRadius: '6px',
          background: '#DCFCE7', fontSize: '0.82rem',
        }}>
          <span style={{ fontWeight: 700, color: '#16A34A' }}>
            已打乱 {count} 次
          </span>
          <span style={{ color: 'var(--ink2)', marginLeft: '0.4rem' }}>
            — 红橘相对、蓝绿相对、白黄相对，不变
          </span>
        </div>
      )}

      <div style={{ display: 'flex', gap: '0.5rem' }}>
        <button
          className="btn btn-primary"
          style={{ fontSize: '0.82rem' }}
          onClick={handleScramble}
        >
          随机打乱
        </button>
        <button
          className="btn btn-outline"
          style={{ fontSize: '0.82rem' }}
          onClick={handleReset}
        >
          重置
        </button>
        <button className="btn btn-outline" style={{ fontSize: '0.82rem', color: '#DC2626', borderColor: '#DC2626' }} onClick={handleIllegalSwap}>非法状态</button>
      </div>
      <div style={{ marginTop: '0.8rem', padding: '0.6rem 0.8rem', borderRadius: '6px', background: '#FEF3C7', borderLeft: '3px solid #F59E0B', fontSize: '0.8rem', color: 'var(--ink2)' }}>更深层的不变量：角块排列的奇偶性和棱块排列的奇偶性始终相同。因此不可能只交换两个角块而其他一切不动——这不是技术不够，是数学约束。</div>
      {showIllegal && (<div style={{ marginTop: '0.6rem', padding: '0.6rem 0.8rem', borderRadius: '6px', background: '#FEE2E2', fontSize: '0.82rem', color: '#DC2626' }}>这是一个<strong>数学上不可能</strong>的状态！只交换两个角块违反了奇偶性守恒——即使你拆散魔方重新组装也无法通过合法转动达到。</div>)}
    </div>
  )
}

/* ============================ 交换子动画演示组件 ============================ */
function CommutatorDemo({ cubeRef }: { cubeRef: React.RefObject<Cube3DViewHandle | null> }) {
  const MOVES = ['R', 'U', "R'", "U'"] as const
  const [step, setStep] = useState(0)
  const [running, setRunning] = useState(false)
  const [done, setDone] = useState(false)
  const handlePlay = useCallback(() => {
    if (running) return
    cubeRef.current?.reset()
    setStep(0); setDone(false); setRunning(true)
    let delay = 600
    for (let i = 0; i < MOVES.length; i++) {
      setTimeout(() => {
        cubeRef.current?.executeMove(MOVES[i])
        setStep(i + 1)
        if (i === MOVES.length - 1) { setDone(true); setRunning(false) }
      }, delay)
      delay += 1000
    }
  }, [running])
  const handleReset = useCallback(() => { cubeRef.current?.reset(); setStep(0); setDone(false); setRunning(false) }, [])
  return (
    <div className="card" style={{ marginBottom: '1rem', borderLeft: '4px solid #8B5CF6' }}>
      <h3 style={{ fontSize: '0.9rem', fontWeight: 700, marginBottom: '0.6rem' }}>交换子演示 [X, Y] = X·Y·X'·Y'</h3>
      <p style={{ fontSize: '0.8rem', color: 'var(--ink2)', marginBottom: '0.8rem' }}>点击播放交换子观察：R·U·R'·U' 只产生 3-循环（3 个角块和 3 个棱块各自轮换，其余不变）</p>
      <div style={{ display: 'flex', gap: '0.3rem', marginBottom: '0.8rem' }}>
        {MOVES.map((move, i) => (<div key={i} style={{ flex: 1, padding: '0.3rem', textAlign: 'center', borderRadius: '4px', fontSize: '0.78rem', fontFamily: 'monospace', background: step > i ? '#EDE9FE' : step === i && running ? '#FDE68A' : 'var(--bg2)', fontWeight: step > i ? 700 : 400, color: step > i ? '#7C3AED' : 'var(--ink2)' }}>{move}</div>))}
      </div>
      {done && <div style={{ marginBottom: '0.8rem', padding: '0.4rem 0.8rem', borderRadius: '6px', background: '#EDE9FE', fontSize: '0.82rem', color: '#7C3AED', fontWeight: 600 }}>交换子完成！只产生了 3-循环（3 角块 + 3 棱块各自轮换）</div>}
      <div style={{ display: 'flex', gap: '0.5rem' }}>
        <button className="btn btn-primary" style={{ fontSize: '0.82rem' }} onClick={handlePlay} disabled={running}>{running ? '播放中...' : '▶ 播放交换子'}</button>
        <button className="btn btn-outline" style={{ fontSize: '0.82rem' }} onClick={handleReset}>重置</button>
      </div>
    </div>
  )
}

